import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [userRole, setUserRole] = useState(''); 
  const [view, setView] = useState('dashboard'); 
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [movimientos, setMovimientos] = useState([]);

  const [showForm, setShowForm] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedId, setSelectedId] = useState(null);
  const [nuevoProd, setNuevoProd] = useState({
    nombre: '', categoria: '', stock: 0, precio_compra: 0, precio_venta: 0, fecha_caducidad: ''
  });

  const cargarDatos = async () => {
    const resStats = await axios.get('http://localhost:5000/api/stats');
    setStats(resStats.data);
    const resProds = await axios.get('http://localhost:5000/api/productos');
    setProductos(resProds.data);
    const resMovs = await axios.get('http://localhost:5000/api/movimientos');
    setMovimientos(resMovs.data);
  };

  useEffect(() => { if (isLoggedIn) cargarDatos(); }, [isLoggedIn]);

  // --- LOGICA DE EDITAR ---
  const prepararEdicion = (prod) => {
    setNuevoProd({
        nombre: prod.nombre, categoria: prod.categoria, stock: prod.stock, 
        precio_compra: prod.precio_compra, precio_venta: prod.precio_venta, 
        fecha_caducidad: prod.fecha_caducidad ? prod.fecha_caducidad.split('T')[0] : ''
    });
    setSelectedId(prod.id);
    setEditMode(true);
    setShowForm(true);
  };

  const guardarProducto = async () => {
    if (editMode) {
      await axios.put(`http://localhost:5000/api/productos/${selectedId}`, nuevoProd);
    } else {
      await axios.post('http://localhost:5000/api/productos', nuevoProd);
    }
    alert("¡Éxito!");
    setShowForm(false); setEditMode(false); cargarDatos();
  };

  const eliminarProducto = async (id) => {
    if (window.confirm("¿Seguro que quieres eliminar este producto?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  const registrarVenta = async (id, cant) => {
      await axios.post('http://localhost:5000/api/movimientos', { id_producto: id, tipo: 'venta', cantidad: cant });
      alert("Venta registrada");
      cargarDatos();
  };

  if (!isLoggedIn) return (
    <div className="login-container">
        <div className="login-card">
            <h2>Mi Tiendita - Acceso</h2>
            <input type="text" placeholder="Usuario" onChange={e => setUsuario(e.target.value)} />
            <input type="password" placeholder="Clave" onChange={e => setPassword(e.target.value)} />
            <button className="btn-entrar" onClick={async () => {
                const res = await axios.post('http://localhost:5000/api/login', {usuario, clave: password});
                setIsLoggedIn(true); setUserRole(res.data.rol);
            }}>Entrar</button>
        </div>
    </div>
  );

  return (
    <div>
      <header className="header">
        <h1>Mi Tiendita - {view.toUpperCase()}</h1>
        <button className="btn-cerrar" onClick={() => setIsLoggedIn(false)}>Cerrar Sesión</button>
      </header>

      <nav className="nav-bar">
        <span className="nav-link" onClick={() => setView('dashboard')}>Dashboard</span>
        {userRole === 'admin' && <span className="nav-link" onClick={() => setView('gestion')}>Inventario</span>}
        <span className="nav-link" onClick={() => setView('movimientos')}>Ventas/Movimientos</span>
      </nav>

      <main style={{ padding: '20px' }}>

        {/* --- VISTA DASHBOARD --- */}
        {view === 'dashboard' && (
          <div className="dashboard-grid">
            <div className="card clickable" onClick={() => setView('bajo_stock')}>
              <h3>⚠️ Bajo Stock</h3>
              <p>{stats.bajo_stock} productos por agotarse. Haz clic para ver.</p>
            </div>
            <div className="card clickable" onClick={() => setView('caducidad')}>
              <h3>📅 Por Caducar</h3>
              <p>Haz clic para ver vencimientos próximos.</p>
            </div>
            <div className="card">
              <h3>💰 Valor Tienda</h3>
              <p>${stats.valor_inventario}</p>
            </div>
          </div>
        )}

        {/* --- VISTA LISTAS FILTRADAS (BAJO STOCK / CADUCIDAD) --- */}
        {(view === 'bajo_stock' || view === 'caducidad') && (
            <div className="card">
                <h3>{view === 'bajo_stock' ? 'Productos Agotándose' : 'Control de Caducidad'}</h3>
                <button onClick={() => setView('dashboard')}>Regresar</button>
                <ul>
                    {productos
                        .filter(p => view === 'bajo_stock' ? p.stock < 10 : p.fecha_caducidad !== null)
                        .map(p => (
                            <li key={p.id}>{p.nombre} - {view === 'bajo_stock' ? `Quedan: ${p.stock}` : `Caduca: ${p.fecha_caducidad.split('T')[0]}`}</li>
                        ))
                    }
                </ul>
            </div>
        )}

        {/* --- VISTA GESTIÓN (INVENTARIO) --- */}
        {view === 'gestion' && (
          <div className="card">
            <button onClick={() => { setShowForm(!showForm); setEditMode(false); setNuevoProd({nombre:'', stock:0, precio_venta:0}); }}>
                {showForm ? 'Cancelar' : '+ Nuevo Producto'}
            </button>
            {showForm && (
                <div className="form-box">
                    <input type="text" placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} />
                    <input type="number" placeholder="Stock" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} />
                    <input type="number" placeholder="Venta $" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({...nuevoProd, precio_venta: e.target.value})} />
                    <button onClick={guardarProducto}>{editMode ? 'Actualizar' : 'Guardar'}</button>
                </div>
            )}
            <table>
                <thead><tr><th>Producto</th><th>Stock</th><th>Precio</th><th>Acciones</th></tr></thead>
                <tbody>
                    {productos.map(p => (
                        <tr key={p.id}>
                            <td>{p.nombre}</td>
                            <td>{p.stock}</td>
                            <td>${p.precio_venta}</td>
                            <td>
                                <button onClick={() => prepararEdicion(p)}>✏️</button>
                                <button onClick={() => eliminarProducto(p.id)}>🗑️</button>
                                <button onClick={() => registrarVenta(p.id, 1)}>💸 Vender 1</button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
          </div>
        )}

        {/* --- VISTA MOVIMIENTOS (HISTORIAL) --- */}
        {view === 'movimientos' && (
            <div className="card">
                <h3>Historial de Ventas</h3>
                <table>
                    <thead><tr><th>Producto</th><th>Tipo</th><th>Cantidad</th><th>Fecha</th></tr></thead>
                    <tbody>
                        {movimientos.map(m => (
                            <tr key={m.id}>
                                <td>{m.nombre}</td>
                                <td style={{color: m.tipo === 'venta' ? 'red' : 'green'}}>{m.tipo}</td>
                                <td>{m.cantidad}</td>
                                <td>{new Date(m.fecha).toLocaleString()}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        )}
      </main>
    </div>
  );
}

export default App;
